// AuthenticationHandler.java - SOAP Security Handler
// ============================================

package com.hr.security;

import javax.xml.namespace.QName;
import javax.xml.soap.*;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

public class AuthenticationHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(AuthenticationHandler.class.getName());
    private static final Map<String, String> API_KEYS = new ConcurrentHashMap<>();
    private static final Map<String, List<Long>> RATE_LIMIT_MAP = new ConcurrentHashMap<>();
    private static final int MAX_REQUESTS_PER_MINUTE = 60;
    private static final long ONE_MINUTE_MS = 60_000L;

    static {
        // In production, load from secure configuration/vault
        API_KEYS.put("hr-admin-key-hash", "HR_ADMIN");
        API_KEYS.put("hr-manager-key-hash", "HR_MANAGER");
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName("http://hr.com/security", "AuthHeader"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (outbound != null && outbound) {
            return true;
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPHeader header = message.getSOAPHeader();

            if (header == null) {
                LOGGER.warning("Authentication failed: No SOAP header present");
                generateSOAPFault(message, "Authentication required");
                return false;
            }

            String apiKey = null;
            String clientId = null;

            Iterator<?> headerElements = header.examineAllHeaderElements();
            while (headerElements.hasNext()) {
                SOAPHeaderElement element = (SOAPHeaderElement) headerElements.next();
                if ("AuthHeader".equals(element.getLocalName())) {
                    Iterator<?> children = element.getChildElements();
                    while (children.hasNext()) {
                        Object child = children.next();
                        if (child instanceof SOAPElement) {
                            SOAPElement soapChild = (SOAPElement) child;
                            if ("ApiKey".equals(soapChild.getLocalName())) {
                                apiKey = soapChild.getTextContent();
                            } else if ("ClientId".equals(soapChild.getLocalName())) {
                                clientId = soapChild.getTextContent();
                            }
                        }
                    }
                }
            }

            if (apiKey == null || apiKey.isEmpty() || clientId == null || clientId.isEmpty()) {
                LOGGER.warning("Authentication failed: Missing credentials");
                generateSOAPFault(message, "Invalid credentials");
                return false;
            }

            String hashedKey = hashApiKey(apiKey);
            if (!API_KEYS.containsKey(hashedKey)) {
                LOGGER.warning("Authentication failed: Invalid API key for client: " + sanitizeLogInput(clientId));
                generateSOAPFault(message, "Authentication failed");
                return false;
            }

            if (!checkRateLimit(clientId)) {
                LOGGER.warning("Rate limit exceeded for client: " + sanitizeLogInput(clientId));
                generateSOAPFault(message, "Rate limit exceeded. Try again later.");
                return false;
            }

            context.put("authenticatedRole", API_KEYS.get(hashedKey));
            context.put("clientId", clientId);
            context.setScope("authenticatedRole", MessageContext.Scope.APPLICATION);
            context.setScope("clientId", MessageContext.Scope.APPLICATION);

            LOGGER.info("Authenticated client: " + sanitizeLogInput(clientId));
            return true;

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error processing SOAP authentication", e);
            return false;
        }
    }

    private boolean checkRateLimit(String clientId) {
        long now = System.currentTimeMillis();
        RATE_LIMIT_MAP.computeIfAbsent(clientId, k -> Collections.synchronizedList(new ArrayList<>()));
        List<Long> timestamps = RATE_LIMIT_MAP.get(clientId);

        synchronized (timestamps) {
            timestamps.removeIf(ts -> now - ts > ONE_MINUTE_MS);
            if (timestamps.size() >= MAX_REQUESTS_PER_MINUTE) {
                return false;
            }
            timestamps.add(now);
        }
        return true;
    }

    private String hashApiKey(String apiKey) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(apiKey.getBytes(StandardCharsets.UTF_8));
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new SecurityException("Hashing algorithm not available", e);
        }
    }

    private void generateSOAPFault(SOAPMessage message, String reason) {
        try {
            SOAPBody body = message.getSOAPBody();
            SOAPFault fault = body.addFault();
            fault.setFaultString(reason);
            fault.setFaultCode(new QName("http://hr.com/fault", "AuthenticationError"));
        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "Error generating SOAP fault", e);
        }
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "").replaceAll("[<>&]", "");
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        LOGGER.warning("SOAP Fault occurred in authentication handler");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

