package com.hr.security;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.logging.Logger;

public final class AuditLogger {

    private static final Logger AUDIT_LOGGER = Logger.getLogger("HR_AUDIT");
    private static final DateTimeFormatter FORMATTER = DateTimeFormatter.ISO_LOCAL_DATE_TIME;

    private AuditLogger() {}

    public static void logAction(String action, String employeeId, String performedBy, String details) {
        String sanitizedAction = sanitize(action);
        String sanitizedEmployeeId = sanitize(employeeId);
        String sanitizedPerformedBy = sanitize(performedBy);
        String sanitizedDetails = sanitize(details);

        String logEntry = String.format("[AUDIT] %s | Action: %s | EmployeeId: %s | PerformedBy: %s | Details: %s",
                LocalDateTime.now().format(FORMATTER),
                sanitizedAction,
                sanitizedEmployeeId,
                sanitizedPerformedBy,
                sanitizedDetails);

        AUDIT_LOGGER.info(logEntry);
    }

    public static void logSecurityEvent(String event, String details) {
        String logEntry = String.format("[SECURITY] %s | Event: %s | Details: %s",
                LocalDateTime.now().format(FORMATTER),
                sanitize(event),
                sanitize(details));

        AUDIT_LOGGER.warning(logEntry);
    }

    private static String sanitize(String input) {
        if (input == null) return "N/A";
        return input.replaceAll("[\\r\\n]", " ").replaceAll("[<>&\"']", "").trim();
    }
}

