package com.hr.data;

import com.hr.model.Employee;
import com.hr.model.PerformanceReview;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

public class EmployeeDataStore {

    private static final EmployeeDataStore INSTANCE = new EmployeeDataStore();
    private final Map<String, Employee> employees = new ConcurrentHashMap<>();

    private EmployeeDataStore() {
        initSampleData();
    }

    public static EmployeeDataStore getInstance() {
        return INSTANCE;
    }

    private void initSampleData() {
        Employee emp1 = new Employee("EMP-000001", "John", "Doe", "john.doe@company.com",
                "Engineering", new BigDecimal("85000.00"), LocalDate.of(2020, 3, 15));
        Employee emp2 = new Employee("EMP-000002", "Jane", "Smith", "jane.smith@company.com",
                "Marketing", new BigDecimal("78000.00"), LocalDate.of(2019, 7, 1));
        Employee emp3 = new Employee("EMP-000003", "Bob", "Johnson", "bob.johnson@company.com",
                "Finance", new BigDecimal("92000.00"), LocalDate.of(2018, 1, 10));

        employees.put(emp1.getEmployeeId(), emp1);
        employees.put(emp2.getEmployeeId(), emp2);
        employees.put(emp3.getEmployeeId(), emp3);
    }

    public Optional<Employee> findById(String employeeId) {
        return Optional.ofNullable(employees.get(employeeId));
    }

    public boolean exists(String employeeId) {
        return employees.containsKey(employeeId);
    }

    public void save(Employee employee) {
        employees.put(employee.getEmployeeId(), employee);
    }

    public void addPerformanceReview(String employeeId, PerformanceReview review) {
        Employee emp = employees.get(employeeId);
        if (emp != null) {
            synchronized (emp) {
                emp.getPerformanceReviews().add(review);
            }
        }
    }
}

