package com.hr.service;

import com.hr.data.EmployeeDataStore;
import com.hr.exception.EmployeeManagementFault;
import com.hr.exception.EmployeeManagementFault.FaultInfo;
import com.hr.model.*;
import com.hr.security.AuditLogger;
import com.hr.security.InputValidator;

import javax.annotation.Resource;
import javax.jws.HandlerChain;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "EmployeeManagementService",
    portName = "EmployeeManagementPort",
    endpointInterface = "com.hr.service.EmployeeManagementService",
    targetNamespace = "http://hr.com/employee/management",
    wsdlLocation = "WEB-INF/wsdl/EmployeeManagement.wsdl"
)
@HandlerChain(file = "handler-chain.xml")
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private final EmployeeDataStore dataStore = EmployeeDataStore.getInstance();

    @Resource
    private WebServiceContext wsContext;

    @Override
    public ServiceResponse updateSalary(SalaryUpdateRequest request) throws EmployeeManagementFault {
        if (request == null) {
            throw createFault("INVALID_REQUEST", "Salary update request cannot be null");
        }

        String employeeId = request.getEmployeeId();
        BigDecimal newSalary = request.getNewSalary();
        String reason = request.getReason();
        String approvedBy = request.getApprovedBy();

        // Validate inputs
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            throw createFault("INVALID_EMPLOYEE_ID", "Invalid employee ID format. Expected: EMP-XXXXXX");
        }
        if (!InputValidator.isValidSalary(newSalary)) {
            throw createFault("INVALID_SALARY", "Salary must be between 0.01 and 10,000,000");
        }
        if (!InputValidator.isValidSafeText(reason)) {
            throw createFault("INVALID_REASON", "Reason contains invalid characters or exceeds length limit");
        }
        if (!InputValidator.isValidEmployeeId(approvedBy)) {
            throw createFault("INVALID_APPROVER", "Invalid approver ID format");
        }

        Optional<Employee> employeeOpt = dataStore.findById(employeeId);
        if (!employeeOpt.isPresent()) {
            throw createFault("EMPLOYEE_NOT_FOUND", "Employee not found: " + employeeId);
        }

        Employee employee = employeeOpt.get();

        if ("TERMINATED".equals(employee.getStatus())) {
            throw createFault("EMPLOYEE_TERMINATED", "Cannot update salary for terminated employee");
        }

        BigDecimal oldSalary = employee.getSalary();

        // Check for excessive salary change (more than 50% increase as a safeguard)
        BigDecimal maxAllowedIncrease = oldSalary.multiply(new BigDecimal("1.5"));
        if (newSalary.compareTo(maxAllowedIncrease) > 0) {
            AuditLogger.logSecurityEvent("EXCESSIVE_SALARY_CHANGE_ATTEMPT",
                    "Employee: " + employeeId + " Old: " + oldSalary + " Requested: " + newSalary);
            throw createFault("EXCESSIVE_CHANGE", "Salary change exceeds maximum allowed threshold. Requires additional approval.");
        }

        synchronized (employee) {
            employee.setSalary(newSalary);
            dataStore.save(employee);
        }

        AuditLogger.logAction("SALARY_UPDATE", employeeId, approvedBy,
                "Old salary: " + oldSalary + " New salary: " + newSalary + " Reason: " + InputValidator.sanitizeText(reason));

        return new ServiceResponse(true, "Salary updated successfully for employee " + employeeId);
    }

    @Override
    public ServiceResponse submitPerformanceReview(PerformanceReview review) throws EmployeeManagementFault {
        if (review == null) {
            throw createFault("INVALID_REQUEST", "Performance review cannot be null");
        }

        String employeeId = review.getEmployeeId();
        String reviewerId = review.getReviewerId();
        int rating = review.getRating();
        String comments = review.getComments();
        String period = review.getPeriod();

        // Validate inputs
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            throw createFault("INVALID_EMPLOYEE_ID", "Invalid employee ID format");
        }
        if (!InputValidator.isValidEmployeeId(reviewerId)) {
            throw createFault("INVALID_REVIEWER_ID", "Invalid reviewer ID format");
        }
        if (!InputValidator.isValidRating(rating)) {
            throw createFault("INVALID_RATING", "Rating must be between 1 and 5");
        }
        if (!InputValidator.isValidSafeText(comments)) {
            throw createFault("INVALID_COMMENTS", "Comments contain invalid characters or exceed length limit");
        }
        if (!InputValidator.isValidPeriod(period)) {
            throw createFault("INVALID_PERIOD", "Period must be in format YYYY-QN (e.g., 2024-Q1)");
        }

        // Prevent self-review
        if (employeeId.equals(reviewerId)) {
            AuditLogger.logSecurityEvent("SELF_REVIEW_ATTEMPT", "Employee " + employeeId + " attempted self-review");
            throw createFault("SELF_REVIEW_NOT_ALLOWED", "Employees cannot review themselves");
        }

        Optional<Employee> employeeOpt = dataStore.findById(employeeId);
        if (!employeeOpt.isPresent()) {
            throw createFault("EMPLOYEE_NOT_FOUND", "Employee not found: " + employeeId);
        }

        Employee employee = employeeOpt.get();
        if ("TERMINATED".equals(employee.getStatus())) {
            throw createFault("EMPLOYEE_TERMINATED", "Cannot submit review for terminated employee");
        }

        // Check for duplicate review in same period by same reviewer
        synchronized (employee) {
            boolean duplicateExists = employee.getPerformanceReviews().stream()
                    .anyMatch(r -> r.getPeriod().equals(period) && r.getReviewerId().equals(reviewerId));

            if (duplicateExists) {
                throw createFault("DUPLICATE_REVIEW", "A review already exists for this period by this reviewer");
            }

            // Generate secure review ID
            String reviewId = "REV-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
            review.setReviewId(reviewId);
            review.setReviewDate(LocalDate.now());
            review.setComments(InputValidator.sanitizeText(comments));

            dataStore.addPerformanceReview(employeeId, review);
        }

        AuditLogger.logAction("PERFORMANCE_REVIEW_SUBMITTED", employeeId, reviewerId,
                "Rating: " + rating + " Period: " + period);

        return new ServiceResponse(true, "Performance review submitted successfully. Review ID: " + review.getReviewId());
    }

    @Override
    public PerformanceReview[] getPerformanceReviews(String employeeId) throws EmployeeManagementFault {
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            throw createFault("INVALID_EMPLOYEE_ID", "Invalid employee ID format");
        }

        Optional<Employee> employeeOpt = dataStore.findById(employeeId);
        if (!employeeOpt.isPresent()) {
            throw createFault("EMPLOYEE_NOT_FOUND", "Employee not found: " + employeeId);
        }

        Employee employee = employeeOpt.get();
        List<PerformanceReview> reviews;
        synchronized (employee) {
            reviews = List.copyOf(employee.getPerformanceReviews());
        }

        AuditLogger.logAction("PERFORMANCE_REVIEWS_RETRIEVED", employeeId, "SYSTEM",
                "Retrieved " + reviews.size() + " reviews");

        return reviews.toArray(new PerformanceReview[0]);
    }

    @Override
    public ServiceResponse terminateEmployee(TerminationRequest request) throws EmployeeManagementFault {
        if (request == null) {
            throw createFault("INVALID_REQUEST", "Termination request cannot be null");
        }

        String employeeId = request.getEmployeeId();
        String reason = request.getReason();
        String terminationType = request.getTerminationType();
        String approvedBy = request.getApprovedBy();
        String effectiveDateStr = request.getEffectiveDate();

        // Validate inputs
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            throw createFault("INVALID_EMPLOYEE_ID", "Invalid employee ID format");
        }
        if (!InputValidator.isValidSafeText(reason)) {
            throw createFault("INVALID_REASON", "Reason contains invalid characters or exceeds length limit");
        }
        if (!InputValidator.isValidTerminationType(terminationType)) {
            throw createFault("INVALID_TERMINATION_TYPE", "Termination type must be VOLUNTARY, INVOLUNTARY, or RETIREMENT");
        }
        if (!InputValidator.isValidEmployeeId(approvedBy)) {
            throw createFault("INVALID_APPROVER", "Invalid approver ID format");
        }
        if (!InputValidator.isValidDateString(effectiveDateStr)) {
            throw createFault("INVALID_DATE", "Effective date must be in ISO format (yyyy-MM-dd)");
        }

        LocalDate effectiveDate = LocalDate.parse(effectiveDateStr, DateTimeFormatter.ISO_LOCAL_DATE);

        // Cannot terminate in the past
        if (effectiveDate.isBefore(LocalDate.now())) {
            throw createFault("INVALID_DATE", "Termination date cannot be in the past");
        }

        // Cannot self-terminate (must be approved by different person)
        if (employeeId.equals(approvedBy)) {
            AuditLogger.logSecurityEvent("SELF_TERMINATION_ATTEMPT", "Employee " + employeeId + " attempted self-termination");
            throw createFault("SELF_TERMINATION_NOT_ALLOWED", "Employees cannot approve their own termination");
        }

        Optional<Employee> employeeOpt = dataStore.findById(employeeId);
        if (!employeeOpt.isPresent()) {
            throw createFault("EMPLOYEE_NOT_FOUND", "Employee not found: " + employeeId);
        }

        Employee employee = employeeOpt.get();

        synchronized (employee) {
            if ("TERMINATED".equals(employee.getStatus())) {
                throw createFault("ALREADY_TERMINATED", "Employee is already terminated");
            }

            employee.setStatus("TERMINATED");
            employee.setTerminationDate(effectiveDate);
            dataStore.save(employee);
        }

        AuditLogger.logAction("EMPLOYEE_TERMINATION", employeeId, approvedBy,
                "Type: " + terminationType + " Effective: " + effectiveDateStr +
                " Reason: " + InputValidator.sanitizeText(reason));

        return new ServiceResponse(true, "Employee " + employeeId + " termination processed. Effective date: " + effectiveDateStr);
    }

    @Override
    public Employee getEmployee(String employeeId) throws EmployeeManagementFault {
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            throw createFault("INVALID_EMPLOYEE_ID", "Invalid employee ID format");
        }

        Optional<Employee> employeeOpt = dataStore.findById(employeeId);
        if (!employeeOpt.isPresent()) {
            throw createFault("EMPLOYEE_NOT_FOUND", "Employee not found: " + employeeId);
        }

        AuditLogger.logAction("EMPLOYEE_RETRIEVED", employeeId, "SYSTEM", "Employee data accessed");

        // Return a copy to prevent external modification
        Employee original = employeeOpt.get();
        Employee copy = new Employee();
        synchronized (original) {
            copy.setEmployeeId(original.getEmployeeId());
            copy.setFirstName(original.getFirstName());
            copy.setLastName(original.getLastName());
            copy.setEmail(original.getEmail());
            copy.setDepartment(original.getDepartment());
            copy.setSalary(original.getSalary());
            copy.setStatus(original.getStatus());
            copy.setHireDate(original.getHireDate());
            copy.setTerminationDate(original.getTerminationDate());
            copy.setPerformanceReviews(List.copyOf(original.getPerformanceReviews()));
        }

        return copy;
    }

    private EmployeeManagementFault createFault(String errorCode, String message) {
        FaultInfo faultInfo = new FaultInfo(errorCode, message);
        LOGGER.log(Level.WARNING, "Service fault: [{0}] {1}", new Object[]{errorCode, message});
        return new EmployeeManagementFault(message, faultInfo);
    }
}

