// ============================================
// EmployeeManagementPublisher.java - Endpoint Publisher
// ============================================

package com.hr;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class EmployeeManagementPublisher {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementPublisher.class.getName());
    private static final String DEFAULT_ADDRESS = "http://localhost:8080/hr/employee-management";

    private Endpoint endpoint;

    public void start(String address) {
        if (address == null || address.isEmpty()) {
            address = DEFAULT_ADDRESS;
        }

        EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
        endpoint = Endpoint.create(serviceImpl);

        // Configure endpoint properties for security
        endpoint.getProperties().put(Endpoint.WSDL_PORT, 
            new javax.xml.namespace.QName("http://hr.com/employee/management", "EmployeeManagementPort"));
        endpoint.getProperties().put(Endpoint.WSDL_SERVICE,
            new javax.xml.namespace.QName("http://hr.com/employee/management", "EmployeeManagementService"));

        endpoint.publish(address);

        LOGGER.info("Employee Management SOAP Service published at: " + address);
        LOGGER.info("WSDL available at: " + address + "?wsdl");
    }

    public void stop() {
        if (endpoint != null && endpoint.isPublished()) {
            endpoint.stop();
            LOGGER.info("Employee Management SOAP Service stopped");
        }
    }

    public boolean isPublished() {
        return endpoint != null && endpoint.isPublished();
    }

    public static void main(String[] args) {
        String address = DEFAULT_ADDRESS;
        if (args.length > 0) {
            address = args[0];
        }

        EmployeeManagementPublisher publisher = new EmployeeManagementPublisher();
        publisher.start(address);

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down Employee Management Service...");
            publisher.stop();
        }));

        LOGGER.info("Service is running. Press Ctrl+C to stop.");

        // Keep the main thread alive
        try {
            Thread.currentThread().join();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            LOGGER.info("Main thread interrupted, shutting down...");
            publisher.stop();
        }
    }
}

// ============================================
// EmployeeManagementServiceTest.java - Unit Tests
// ============================================

package com.hr.service;

import com.hr.exception.EmployeeManagementFault;
import com.hr.model.*;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.logging.Logger;

public class EmployeeManagementServiceTest {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceTest.class.getName());

    public static void main(String[] args) {
        EmployeeManagementServiceImpl service = new EmployeeManagementServiceImpl();

        testGetEmployee(service);
        testUpdateSalary(service);
        testSubmitPerformanceReview(service);
        testTerminateEmployee(service);
        testInvalidInputs(service);
        testSecurityConstraints(service);

        LOGGER.info("All tests completed.");
    }

    private static void testGetEmployee(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Get Employee ===");
        try {
            Employee emp = service.getEmployee("EMP-000001");
            assert emp != null : "Employee should not be null";
            assert "John".equals(emp.getFirstName()) : "First name should be John";
            assert "ACTIVE".equals(emp.getStatus()) : "Status should be ACTIVE";
            LOGGER.info("PASSED: Get employee");
        } catch (EmployeeManagementFault e) {
            LOGGER.severe("FAILED: " + e.getMessage());
        }
    }

    private static void testUpdateSalary(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Update Salary ===");
        try {
            SalaryUpdateRequest request = new SalaryUpdateRequest();
            request.setEmployeeId("EMP-000001");
            request.setNewSalary(new BigDecimal("90000.00"));
            request.setReason("Annual performance raise");
            request.setApprovedBy("EMP-000003");

            ServiceResponse response = service.updateSalary(request);
            assert response.isSuccess() : "Salary update should succeed";
            LOGGER.info("PASSED: Update salary - " + response.getMessage());

            Employee emp = service.getEmployee("EMP-000001");
            assert emp.getSalary().compareTo(new BigDecimal("90000.00")) == 0 : "Salary should be updated";
            LOGGER.info("PASSED: Salary verified");
        } catch (EmployeeManagementFault e) {
            LOGGER.severe("FAILED: " + e.getMessage());
        }
    }

    private static void testSubmitPerformanceReview(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Submit Performance Review ===");
        try {
            PerformanceReview review = new PerformanceReview();
            review.setEmployeeId("EMP-000001");
            review.setReviewerId("EMP-000003");
            review.setRating(4);
            review.setComments("Excellent performance this quarter");
            review.setPeriod("2024-Q1");

            ServiceResponse response = service.submitPerformanceReview(review);
            assert response.isSuccess() : "Review submission should succeed";
            LOGGER.info("PASSED: Submit review - " + response.getMessage());

            PerformanceReview[] reviews = service.getPerformanceReviews("EMP-000001");
            assert reviews.length == 1 : "Should have 1 review";
            assert reviews[0].getRating() == 4 : "Rating should be 4";
            LOGGER.info("PASSED: Review retrieval verified");
        } catch (EmployeeManagementFault e) {
            LOGGER.severe("FAILED: " + e.getMessage());
        }
    }

    private static void testTerminateEmployee(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Terminate Employee ===");
        try {
            TerminationRequest request = new TerminationRequest();
            request.setEmployeeId("EMP-000002");
            request.setReason("Position eliminated");
            request.setTerminationType("INVOLUNTARY");
            request.setApprovedBy("EMP-000003");
            request.setEffectiveDate(LocalDate.now().plusDays(14).format(DateTimeFormatter.ISO_LOCAL_DATE));

            ServiceResponse response = service.terminateEmployee(request);
            assert response.isSuccess() : "Termination should succeed";
            LOGGER.info("PASSED: Terminate employee - " + response.getMessage());

            Employee emp = service.getEmployee("EMP-000002");
            assert "TERMINATED".equals(emp.getStatus()) : "Status should be TERMINATED";
            LOGGER.info("PASSED: Termination status verified");
        } catch (EmployeeManagementFault e) {
            LOGGER.severe("FAILED: " + e.getMessage());
        }
    }

    private static void testInvalidInputs(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Invalid Inputs ===");

        // Invalid employee ID
        try {
            service.getEmployee("INVALID-ID");
            LOGGER.severe("FAILED: Should have thrown fault for invalid ID");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Invalid employee ID rejected - " + e.getFaultInfo().getErrorCode());
        }

        // Invalid salary
        try {
            SalaryUpdateRequest request = new SalaryUpdateRequest();
            request.setEmployeeId("EMP-000001");
            request.setNewSalary(new BigDecimal("-1000"));
            request.setReason("Test");
            request.setApprovedBy("EMP-000003");
            service.updateSalary(request);
            LOGGER.severe("FAILED: Should have thrown fault for negative salary");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Invalid salary rejected - " + e.getFaultInfo().getErrorCode());
        }

        // Invalid rating
        try {
            PerformanceReview review = new PerformanceReview();
            review.setEmployeeId("EMP-000001");
            review.setReviewerId("EMP-000003");
            review.setRating(10);
            review.setComments("Test");
            review.setPeriod("2024-Q2");
            service.submitPerformanceReview(review);
            LOGGER.severe("FAILED: Should have thrown fault for invalid rating");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Invalid rating rejected - " + e.getFaultInfo().getErrorCode());
        }

        // Past termination date
        try {
            TerminationRequest request = new TerminationRequest();
            request.setEmployeeId("EMP-000001");
            request.setReason("Test");
            request.setTerminationType("VOLUNTARY");
            request.setApprovedBy("EMP-000003");
            request.setEffectiveDate("2020-01-01");
            service.terminateEmployee(request);
            LOGGER.severe("FAILED: Should have thrown fault for past date");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Past termination date rejected - " + e.getFaultInfo().getErrorCode());
        }
    }

    private static void testSecurityConstraints(EmployeeManagementServiceImpl service) {
        LOGGER.info("=== Test: Security Constraints ===");

        // Self-review prevention
        try {
            PerformanceReview review = new PerformanceReview();
            review.setEmployeeId("EMP-000001");
            review.setReviewerId("EMP-000001");
            review.setRating(5);
            review.setComments("I am great");
            review.setPeriod("2024-Q3");
            service.submitPerformanceReview(review);
            LOGGER.severe("FAILED: Should have prevented self-review");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Self-review prevented - " + e.getFaultInfo().getErrorCode());
        }

        // Self-termination prevention
        try {
            TerminationRequest request = new TerminationRequest();
            request.setEmployeeId("EMP-000001");
            request.setReason("Test");
            request.setTerminationType("VOLUNTARY");
            request.setApprovedBy("EMP-000001");
            request.setEffectiveDate(LocalDate.now().plusDays(1).format(DateTimeFormatter.ISO_LOCAL_DATE));
            service.terminateEmployee(request);
            LOGGER.severe("FAILED: Should have prevented self-termination");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Self-termination prevented - " + e.getFaultInfo().getErrorCode());
        }

        // Excessive salary change
        try {
            SalaryUpdateRequest request = new SalaryUpdateRequest();
            request.setEmployeeId("EMP-000001");
            request.setNewSalary(new BigDecimal("5000000.00"));
            request.setReason("Huge raise");
            request.setApprovedBy("EMP-000003");
            service.updateSalary(request);
            LOGGER.severe("FAILED: Should have flagged excessive salary change");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Excessive salary change prevented - " + e.getFaultInfo().getErrorCode());
        }

        // Operations on terminated employee
        try {
            SalaryUpdateRequest request = new SalaryUpdateRequest();
            request.setEmployeeId("EMP-000002");
            request.setNewSalary(new BigDecimal("80000.00"));
            request.setReason("Test");
            request.setApprovedBy("EMP-000003");
            service.updateSalary(request);
            LOGGER.severe("FAILED: Should have prevented salary update on terminated employee");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("PASSED: Terminated employee salary update prevented - " + e.getFaultInfo().getErrorCode());
        }
    }
}